{
var cells = GetInt(parameters, "cellCount", 4);
        var seed = GetInt(parameters, "seed", 0);
        var wallWidth = GetFloat(parameters, "wallWidth", 0.18f);
        var feather = GetFloat(parameters, "feather", 0.5f);
        var bump = GetFloat(parameters, "bump", 0.25f);
        var colorA = GetColor(parameters, "colorA", Color.FromRgb(230, 230, 230));
        var colorB = GetColor(parameters, "colorB", Color.FromRgb(24, 24, 24));
        var invert = GetBool(parameters, "invert", false);

        var aR = colorA.R / 255f;
        var aG = colorA.G / 255f;
        var aB = colorA.B / 255f;
        var bR = colorB.R / 255f;
        var bG = colorB.G / 255f;
        var bB = colorB.B / 255f;

        var size = context.TileSize;
        var buffer = new PixelBuffer(size, size);

        var layout = GetChoice(parameters, "arrangement", "random");

        // Precompute hex parameters if needed
        float hexWidth = 0f, hexHeight = 0f;
        int hexCols = 0, hexRows = 0;
        if (layout == "hexagonal")
        {
            // Choose integer columns/rows so hex cell spacing divides the tile as closely
            // as possible while preserving the correct hex aspect ratio (height = width * sqrt(3)/2).
            // Special-case handling when `cells == 3` to avoid degenerate rounding that produced
            // inconsistent hex geometry (which caused visible artifacts).
            var sqrt3 = MathF.Sqrt(3f);

            if (cells == 3)
            {
                // Start with desired columns equal to the cell count, then compute rows
                // based on the hex aspect ratio and round to nearest integer. Then
                // recompute width/height so the relationship height = width * sqrt3/2
                // holds for the final integer grid.
                var cols = Math.Max(1, cells);
                var hexW = (float)size / cols;
                var hexH = hexW * sqrt3 / 2f;
                var rows = Math.Max(1, (int)MathF.Round(size / hexH));

                // Recompute so height/width maintain proper hex proportions
                hexH = (float)size / rows;
                hexW = hexH * 2f / sqrt3;
                cols = Math.Max(1, (int)MathF.Round(size / hexW));

                hexCols = cols;
                hexRows = rows;
                hexWidth = (float)size / hexCols;
                hexHeight = hexWidth * sqrt3 / 2f;
            }
            else
            {
                // Existing iterative approach for general case
                var cols = Math.Max(1, cells);

                // Iterate to find integer cols/rows that make hexWidth/hexHeight align with tile size.
                float w = (float)size / cols;
                float h = w * sqrt3 / 2f;
                var rows = Math.Max(1, (int)MathF.Round(size / h));

                for (int it = 0; it < 2; it++)
                {
                    h = (float)size / rows;
                    w = h * 2f / sqrt3;
                    cols = Math.Max(1, (int)MathF.Round(size / w));
                    w = (float)size / cols;
                    h = w * sqrt3 / 2f;
                    rows = Math.Max(1, (int)MathF.Round(size / h));
                }

                hexCols = cols;
                hexRows = rows;
                hexWidth = (float)size / hexCols;
                hexHeight = (float)size / hexRows;
            }
        }

        // Local helper: compute tileable hex-grid Voronoi distances normalized by hexWidth
        void TileableHexVoronoi(float px, float py, out float nearest, out float secondNearest)
        {
            nearest = float.MaxValue;
            secondNearest = float.MaxValue;

            if (hexCols <= 0 || hexRows <= 0)
                return;

            // Determine base row first, then compute base column using the
            // horizontal offset for staggered (odd) rows. This ensures the
            // correct hex cell is chosen for rows that are offset by half
            // a column, which fixes layout artifacts when columns/rows are
            // small (for example when "cellCount" == 3).
            var baseRow = (int)MathF.Floor(py / hexHeight);
            var rowOffset = ((baseRow & 1) != 0) ? hexWidth * 0.5f : 0f;
            var baseCol = (int)MathF.Floor((px - rowOffset) / hexWidth);

            for (int ro = -2; ro <= 2; ro++)
            {
                for (int co = -2; co <= 2; co++)
                {
                    var c = baseCol + co;
                    var r = baseRow + ro;

                    // compute center position for flat-top hex grid with horizontal offset on odd rows
                    var cxPos = c * hexWidth + ((r & 1) != 0 ? hexWidth * 0.5f : 0f);
                    var cyPos = r * hexHeight;

                    // compute periodic delta (tile repeats over 'size')
                    var dx = px - cxPos;
                    var dy = py - cyPos;
                    dx -= MathF.Round(dx / size) * size;
                    dy -= MathF.Round(dy / size) * size;

                    var dist = MathF.Sqrt(dx * dx + dy * dy);
                    if (dist < nearest)
                    {
                        secondNearest = nearest;
                        nearest = dist;
                    }
                    else if (dist < secondNearest)
                    {
                        secondNearest = dist;
                    }
                }
            }

            // normalize by hexWidth to be comparable with other code
            var denom = MathF.Max(1e-6f, hexWidth);
            nearest = Math.Clamp(nearest / denom, 0f, 1f);
            secondNearest = Math.Clamp(secondNearest / denom, 0f, 1f);
        }

        // Local helper: tileable Voronoi using float cell size so period equals `size` in pixels.
        void TileableVoronoiFloat(float x, float y, float cellSizeFloat, int periodInCells, int seedParam, out float nearestOut, out float secondOut)
        {
            nearestOut = float.MaxValue;
            secondOut = float.MaxValue;

            var periodSize = (float)size; // tile repeats every `size` pixels

            var cellX0 = (int)MathF.Floor(x / cellSizeFloat);
            var cellY0 = (int)MathF.Floor(y / cellSizeFloat);

            // Expand neighbor search to cover additional periodic candidates.
            // For small `cells` values (for example 3) the Voronoi feature can
            // wrap around the tile boundary; considering a larger neighborhood
            // avoids missing the true nearest points and eliminates visible
            // artifacts for low cell counts.
            for (var dy = -2; dy <= 2; dy++)
            {
                for (var dx = -2; dx <= 2; dx++)
                {
                    var cx = cellX0 + dx;
                    var cy = cellY0 + dy;

                    var wrappedX = Mod(cx, periodInCells);
                    var wrappedY = Mod(cy, periodInCells);

                    var jitterX = HashToUnit(wrappedX, wrappedY, seedParam) - 0.5f;
                    var jitterY = HashToUnit(wrappedX, wrappedY, seedParam + 19) - 0.5f;

                    var pointX = (wrappedX + 0.5f + jitterX) * cellSizeFloat;
                    var pointY = (wrappedY + 0.5f + jitterY) * cellSizeFloat;

                    var ddx = pointX - x;
                    var ddy = pointY - y;
                    ddx -= MathF.Round(ddx / periodSize) * periodSize;
                    ddy -= MathF.Round(ddy / periodSize) * periodSize;

                    var dist = MathF.Sqrt(ddx * ddx + ddy * ddy);
                    if (dist < nearestOut)
                    {
                        secondOut = nearestOut;
                        nearestOut = dist;
                    }
                    else if (dist < secondOut)
                    {
                        secondOut = dist;
                    }
                }
            }

            var denom = MathF.Max(1e-6f, cellSizeFloat);
            nearestOut = Math.Clamp(nearestOut / denom, 0f, 1f);
            secondOut = Math.Clamp(secondOut / denom, 0f, 1f);
        }

        // Ensure valid parameters
        cells = Math.Max(1, cells);
        feather = Math.Max(0f, feather);
        wallWidth = Math.Clamp(wallWidth, 0f, 1f);

        // Use float cell size to ensure perfect tiling even when `size` is not divisible by `cells`.
        var cellSizeF = Math.Max(1f, (float)size / (float)cells);

        // Per-pixel evaluation: sample at pixel centers for stable results
        buffer.ParallelForEachPixel((x, y) =>
        {
            var px = x + 0.5f;
            var py = y + 0.5f;

            float nearest, secondNearest;
            if (layout == "hexagonal")
            {
                TileableHexVoronoi(px, py, out nearest, out secondNearest);
                // cx/cy not used for hex layout
            }
            else
            {
                // Use a local float-aware tileable Voronoi to avoid seams when size % cells != 0
                TileableVoronoiFloat(px, py, cellSizeF, cells, seed, out nearest, out secondNearest);
            }

            // nearest is normalized by cellSize in [0,1]
            // interior mask: full inside cells, falling to 0 across walls
            var wall = SmoothStep(wallWidth - feather, wallWidth + feather, nearest);
            var interior = 1f - wall; // interior = 1 at cell center, 0 at walls

            // ridge: highlight borders using difference between first and second distance
            var d = MathF.Max(0f, secondNearest - nearest); // larger in center, smaller near border
            // normalize difference heuristically (0.3 chosen to control sharpness)
            var ridge = Math.Clamp(d / 0.3f, 0f, 1f);
            ridge = SmoothStep(0f, 1f, ridge);

            // Combine interior and ridge to get final luminance
            var value = interior + bump * (1f - interior) * ridge;
            value = Math.Clamp(value, 0f, 1f);

            if (invert) value = 1f - value;

            // Lerp between background (B) and interior color (A)
            var outR = bR * (1f - value) + aR * value;
            var outG = bG * (1f - value) + aG * value;
            var outB = bB * (1f - value) + aB * value;

            buffer.SetPixel(x, y, outR, outG, outB, 1f);
        });

        return buffer;
}
